import { CircuitBreaker, CircuitBreakerState, CircuitBreakerRegistry } from './circuit-breaker';

/**
 * CircuitBreaker Unit Tests
 * 
 * Comprehensive test suite covering:
 * - CLOSED → OPEN transition after threshold failures
 * - OPEN → HALF_OPEN transition after timeout
 * - HALF_OPEN → CLOSED transition on success
 * - HALF_OPEN → OPEN transition on failure
 * - Edge cases and state transitions
 */

describe('CircuitBreaker', () => {
  // Test configuration
  const failureThreshold = 3;
  const resetTimeoutSeconds = 1; // Short for testing
  const successThreshold = 1;

  describe('Initial State', () => {
    it('should start in CLOSED state', () => {
      const breaker = new CircuitBreaker('test');
      expect(breaker.getState()).toBe(CircuitBreakerState.CLOSED);
    });

    it('should be available when closed', () => {
      const breaker = new CircuitBreaker('test');
      expect(breaker.isAvailable()).toBe(true);
    });

    it('should accept custom configuration', () => {
      const breaker = new CircuitBreaker('custom', {
        failureThreshold: 5,
        resetTimeoutSeconds: 10,
        successThreshold: 2,
      });
      expect(breaker.getState()).toBe(CircuitBreakerState.CLOSED);
    });
  });

  // ============================================
  // CLOSED → OPEN TRANSITION
  // ============================================

  describe('CLOSED → OPEN Transition', () => {
    /**
     * Test: should open circuit after threshold failures
     * Validates CLOSED → OPEN transition
     */
    it('should open circuit after threshold failures', async () => {
      const breaker = new CircuitBreaker('test', {
        failureThreshold,
        resetTimeoutSeconds: 100, // Long timeout
        successThreshold,
      });

      // Execute failing operations until threshold
      for (let i = 0; i < failureThreshold; i++) {
        await expect(breaker.execute(() => Promise.reject(new Error('Fail')))).rejects.toThrow();
      }

      expect(breaker.getState()).toBe(CircuitBreakerState.OPEN);
    });

    /**
     * Test: should not open circuit before threshold
     * Validates failure counting
     */
    it('should not open circuit before threshold', async () => {
      const breaker = new CircuitBreaker('test', {
        failureThreshold: 5,
        resetTimeoutSeconds: 100,
        successThreshold,
      });

      // Execute fewer failures than threshold
      await expect(breaker.execute(() => Promise.reject(new Error('Fail')))).rejects.toThrow();
      await expect(breaker.execute(() => Promise.reject(new Error('Fail')))).rejects.toThrow();

      expect(breaker.getState()).toBe(CircuitBreakerState.CLOSED);
    });

    /**
     * Test: should reset failure count on success
     * Validates failure reset behavior
     */
    it('should reset failure count on success', async () => {
      const breaker = new CircuitBreaker('test', {
        failureThreshold,
        resetTimeoutSeconds: 100,
        successThreshold,
      });

      // Fail twice, then succeed - should reset
      await expect(breaker.execute(() => Promise.reject(new Error('Fail')))).rejects.toThrow();
      await expect(breaker.execute(() => Promise.reject(new Error('Fail')))).rejects.toThrow();
      await breaker.execute(() => Promise.resolve('success'));

      // Now fail 3 times - should NOT open yet (failures were reset)
      await expect(breaker.execute(() => Promise.reject(new Error('Fail')))).rejects.toThrow();
      await expect(breaker.execute(() => Promise.reject(new Error('Fail')))).rejects.toThrow();
      expect(breaker.getState()).toBe(CircuitBreakerState.CLOSED);

      // Fail 3 more times to reach threshold
      await expect(breaker.execute(() => Promise.reject(new Error('Fail')))).rejects.toThrow();
      expect(breaker.getState()).toBe(CircuitBreakerState.OPEN);
    });
  });

  // ============================================
  // OPEN → HALF_OPEN TRANSITION
  // ============================================

  describe('OPEN → HALF_OPEN Transition', () => {
    /**
     * Test: should transition to HALF_OPEN after timeout
     * Validates OPEN → HALF_OPEN transition
     */
    it('should transition to HALF_OPEN after timeout', async () => {
      const breaker = new CircuitBreaker('test', {
        failureThreshold: 2,
        resetTimeoutSeconds: 1, // Short timeout for testing
        successThreshold,
      });

      // Open the circuit
      await expect(breaker.execute(() => Promise.reject(new Error('Fail')))).rejects.toThrow();
      await expect(breaker.execute(() => Promise.reject(new Error('Fail')))).rejects.toThrow();
      expect(breaker.getState()).toBe(CircuitBreakerState.OPEN);

      // Wait for timeout
      await new Promise((resolve) => setTimeout(resolve, 1100));

      // Next call should transition to HALF_OPEN
      await breaker.execute(() => Promise.resolve('test'));
      expect(breaker.getState()).toBe(CircuitBreakerState.HALF_OPEN);
    });

    /**
     * Test: should throw when circuit is open and timeout not elapsed
     * Validates OPEN state rejection
     */
    it('should throw when circuit is open and timeout not elapsed', async () => {
      const breaker = new CircuitBreaker('test', {
        failureThreshold: 2,
        resetTimeoutSeconds: 10, // Long timeout
        successThreshold,
      });

      // Open the circuit
      await expect(breaker.execute(() => Promise.reject(new Error('Fail')))).rejects.toThrow();
      await expect(breaker.execute(() => Promise.reject(new Error('Fail')))).rejects.toThrow();
      expect(breaker.getState()).toBe(CircuitBreakerState.OPEN);

      // Try to execute - should throw
      await expect(breaker.execute(() => Promise.resolve('test'))).rejects.toThrow(
        'Circuit breaker [test] is OPEN',
      );
    });

    /**
     * Test: isAvailable should return true when timeout elapsed
     * Validates availability check
     */
    it('isAvailable should return true when timeout elapsed', async () => {
      const breaker = new CircuitBreaker('test', {
        failureThreshold: 2,
        resetTimeoutSeconds: 1,
        successThreshold,
      });

      // Open the circuit
      await expect(breaker.execute(() => Promise.reject(new Error('Fail')))).rejects.toThrow();
      await expect(breaker.execute(() => Promise.reject(new Error('Fail')))).rejects.toThrow();

      // Wait for timeout
      await new Promise((resolve) => setTimeout(resolve, 1100));

      // isAvailable should now return true
      expect(breaker.isAvailable()).toBe(true);
    });
  });

  // ============================================
  // HALF_OPEN → CLOSED TRANSITION
  // ============================================

  describe('HALF_OPEN → CLOSED Transition', () => {
    /**
     * Test: should close circuit on success in HALF_OPEN
     * Validates HALF_OPEN → CLOSED transition
     */
    it('should close circuit on success in HALF_OPEN', async () => {
      const breaker = new CircuitBreaker('test', {
        failureThreshold: 2,
        resetTimeoutSeconds: 1,
        successThreshold: 1,
      });

      // Open the circuit
      await expect(breaker.execute(() => Promise.reject(new Error('Fail')))).rejects.toThrow();
      await expect(breaker.execute(() => Promise.reject(new Error('Fail')))).rejects.toThrow();

      // Wait for timeout to transition to HALF_OPEN
      await new Promise((resolve) => setTimeout(resolve, 1100));

      // Success should close the circuit
      const result = await breaker.execute(() => Promise.resolve('success'));
      expect(result).toBe('success');
      expect(breaker.getState()).toBe(CircuitBreakerState.CLOSED);
    });

    /**
     * Test: should require multiple successes if successThreshold > 1
     * Validates success threshold
     */
    it('should require multiple successes if successThreshold > 1', async () => {
      const breaker = new CircuitBreaker('test', {
        failureThreshold: 2,
        resetTimeoutSeconds: 1,
        successThreshold: 2,
      });

      // Open the circuit
      await expect(breaker.execute(() => Promise.reject(new Error('Fail')))).rejects.toThrow();
      await expect(breaker.execute(() => Promise.reject(new Error('Fail')))).rejects.toThrow();

      // Wait for timeout
      await new Promise((resolve) => setTimeout(resolve, 1100));

      // First success - still HALF_OPEN
      await breaker.execute(() => Promise.resolve('success1'));
      expect(breaker.getState()).toBe(CircuitBreakerState.HALF_OPEN);

      // Second success - should close
      await breaker.execute(() => Promise.resolve('success2'));
      expect(breaker.getState()).toBe(CircuitBreakerState.CLOSED);
    });
  });

  // ============================================
  // HALF_OPEN → OPEN TRANSITION
  // ============================================

  describe('HALF_OPEN → OPEN Transition', () => {
    /**
     * Test: should reopen circuit on failure in HALF_OPEN
     * Validates HALF_OPEN → OPEN transition
     */
    it('should reopen circuit on failure in HALF_OPEN', async () => {
      const breaker = new CircuitBreaker('test', {
        failureThreshold: 2,
        resetTimeoutSeconds: 1,
        successThreshold: 1,
      });

      // Open the circuit
      await expect(breaker.execute(() => Promise.reject(new Error('Fail')))).rejects.toThrow();
      await expect(breaker.execute(() => Promise.reject(new Error('Fail')))).rejects.toThrow();

      // Wait for timeout
      await new Promise((resolve) => setTimeout(resolve, 1100));

      // First call enters HALF_OPEN
      await breaker.execute(() => Promise.resolve('half-open-call'));

      // Failure should reopen
      await expect(breaker.execute(() => Promise.reject(new Error('Fail in HALF_OPEN')))).rejects.toThrow();
      expect(breaker.getState()).toBe(CircuitBreakerState.OPEN);
    });
  });

  // ============================================
  // STATS AND RESET
  // ============================================

  describe('Stats and Reset', () => {
    /**
     * Test: should track failure count
     * Validates statistics
     */
    it('should track failure count', async () => {
      const breaker = new CircuitBreaker('test', {
        failureThreshold: 5,
        resetTimeoutSeconds: 100,
        successThreshold,
      });

      await expect(breaker.execute(() => Promise.reject(new Error('Fail')))).rejects.toThrow();
      await expect(breaker.execute(() => Promise.reject(new Error('Fail')))).rejects.toThrow();

      const stats = breaker.getStats();
      expect(stats.failureCount).toBe(2);
    });

    /**
     * Test: should track success count
     * Validates success statistics
     */
    it('should track success count', async () => {
      const breaker = new CircuitBreaker('test', {
        failureThreshold: 5,
        resetTimeoutSeconds: 100,
        successThreshold: 2,
      });

      await breaker.execute(() => Promise.resolve('success1'));
      await breaker.execute(() => Promise.resolve('success2'));

      const stats = breaker.getStats();
      expect(stats.successCount).toBe(2);
    });

    /**
     * Test: should manually reset circuit breaker
     * Validates reset functionality
     */
    it('should manually reset circuit breaker', async () => {
      const breaker = new CircuitBreaker('test', {
        failureThreshold: 2,
        resetTimeoutSeconds: 100,
        successThreshold,
      });

      // Open the circuit
      await expect(breaker.execute(() => Promise.reject(new Error('Fail')))).rejects.toThrow();
      await expect(breaker.execute(() => Promise.reject(new Error('Fail')))).rejects.toThrow();
      expect(breaker.getState()).toBe(CircuitBreakerState.OPEN);

      // Reset
      breaker.reset();

      // Should be closed now
      expect(breaker.getState()).toBe(CircuitBreakerState.CLOSED);
      expect(breaker.isAvailable()).toBe(true);

      const stats = breaker.getStats();
      expect(stats.failureCount).toBe(0);
      expect(stats.successCount).toBe(0);
    });
  });

  // ============================================
  // EDGE CASES
  // ============================================

  describe('Edge Cases', () => {
    /**
     * Test: should handle sync errors
     * Validates synchronous error handling
     */
    it('should handle sync errors', () => {
      const breaker = new CircuitBreaker('test', {
        failureThreshold: 2,
        resetTimeoutSeconds: 100,
        successThreshold,
      });

      // Sync throw
      expect(() => breaker.execute(() => {
        throw new Error('Sync error');
      })).toThrow();

      expect(breaker.getState()).toBe(CircuitBreakerState.CLOSED); // Only 1 failure

      expect(() => breaker.execute(() => {
        throw new Error('Sync error 2');
      })).toThrow();

      expect(breaker.getState()).toBe(CircuitBreakerState.OPEN);
    });

    /**
     * Test: should handle successful execution with return value
     * Validates return value passing
     */
    it('should pass through return value on success', async () => {
      const breaker = new CircuitBreaker('test');
      const result = await breaker.execute(() => 
        Promise.resolve({ data: 'test', count: 42 })
      );
      expect(result).toEqual({ data: 'test', count: 42 });
    });

    /**
     * Test: should handle different error types
     * Validates error handling flexibility
     */
    it('should handle different error types', async () => {
      const breaker = new CircuitBreaker('test', {
        failureThreshold: 3,
        resetTimeoutSeconds: 100,
        successThreshold,
      });

      // String error
      await expect(breaker.execute(() => Promise.reject('string error'))).rejects.toBe('string error');
      // Object error
      await expect(breaker.execute(() => Promise.reject({ code: 'ERR' }))).rejects.toEqual({ code: 'ERR' });
      // Number error
      await expect(breaker.execute(() => Promise.reject(500))).rejects.toBe(500);

      expect(breaker.getState()).toBe(CircuitBreakerState.OPEN);
    });

    /**
     * Test: should work with async/await
     * Validates async handling
     */
    it('should work with async/await', async () => {
      const breaker = new CircuitBreaker('test', {
        failureThreshold: 2,
        resetTimeoutSeconds: 100,
        successThreshold,
      });

      const asyncFunction = async () => {
        await new Promise((resolve) => setTimeout(resolve, 10));
        return 'async result';
      };

      const result = await breaker.execute(asyncFunction);
      expect(result).toBe('async result');
    });
  });
});

describe('CircuitBreakerRegistry', () => {
  describe('Basic Operations', () => {
    it('should create circuit breaker on first access', () => {
      const registry = new CircuitBreakerRegistry();
      const breaker = registry.getBreaker('test');
      expect(breaker).toBeDefined();
    });

    it('should return same breaker on subsequent access', () => {
      const registry = new CircuitBreakerRegistry();
      const breaker1 = registry.getBreaker('test');
      const breaker2 = registry.getBreaker('test');
      expect(breaker1).toBe(breaker2);
    });

    it('should create separate breakers for different names', () => {
      const registry = new CircuitBreakerRegistry();
      const breaker1 = registry.getBreaker('test1');
      const breaker2 = registry.getBreaker('test2');
      expect(breaker1).not.toBe(breaker2);
    });
  });

  describe('Stats', () => {
    const successThreshold = 1;

    it('should get stats for all breakers', () => {
      const registry = new CircuitBreakerRegistry();
      registry.getBreaker('breaker1');
      registry.getBreaker('breaker2');

      const stats = registry.getAllStats();
      expect(Object.keys(stats)).toContain('breaker1');
      expect(Object.keys(stats)).toContain('breaker2');
    });

    it('should reset all breakers', async () => {
      const registry = new CircuitBreakerRegistry();
      const breaker = registry.getBreaker('test', {
        failureThreshold: 2,
        resetTimeoutSeconds: 100,
        successThreshold,
      });

      // Open the circuit
      await expect(breaker.execute(() => Promise.reject(new Error('Fail')))).rejects.toThrow();
      await expect(breaker.execute(() => Promise.reject(new Error('Fail')))).rejects.toThrow();
      expect(breaker.getState()).toBe(CircuitBreakerState.OPEN);

      // Reset all
      registry.resetAll();

      expect(breaker.getState()).toBe(CircuitBreakerState.CLOSED);
    });
  });
});
